from __future__ import annotations

import itertools
import logging
import ssl
import typing

from .._backends.sync import SyncBackend
from .._backends.base import SOCKET_OPTION, NetworkBackend, NetworkStream
from .._exceptions import ConnectError, ConnectTimeout
from .._models import Origin, Request, Response
from .._ssl import default_ssl_context
from .._synchronization import Lock
from .._trace import Trace
from .http11 import HTTP11Connection
from .interfaces import ConnectionInterface

RETRIES_BACKOFF_FACTOR = 0.5  # 0s, 0.5s, 1s, 2s, 4s, etc.


logger = logging.getLogger("httpcore.connection")


def exponential_backoff(factor: float) -> typing.Iterator[float]:
    """
    Generate a geometric sequence that has a ratio of 2 and starts with 0.

    For example:
    - `factor = 2`: `0, 2, 4, 8, 16, 32, 64, ...`
    - `factor = 3`: `0, 3, 6, 12, 24, 48, 96, ...`
    """
    yield 0
    for n in itertools.count():
        yield factor * 2**n


class HTTPConnection(ConnectionInterface):
    def __init__(
        self,
        origin: Origin,
        ssl_context: ssl.SSLContext | None = None,
        keepalive_expiry: float | None = None,
        http1: bool = True,
        http2: bool = False,
        retries: int = 0,
        local_address: str | None = None,
        uds: str | None = None,
        network_backend: NetworkBackend | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> None:
        """
        Initialize a connection wrapper that manages a single underlying
        connection instance (either HTTP/1.1 or HTTP/2) for the given origin.

        Parameters:
        - origin: The origin (host/port/scheme) this connection is for.
        - ssl_context: Optional SSL context to use for TLS handshakes.
        - keepalive_expiry: Optional time (epoch seconds) when keep-alive should expire.
        - http1: Whether HTTP/1.1 is allowed.
        - http2: Whether HTTP/2 is allowed.
        - retries: Number of connection retries to attempt on connect failure.
        - local_address: Optional local address to bind to for outgoing connections.
        - uds: Optional Unix domain socket path to connect to instead of TCP.
        - network_backend: Optional network backend implementation.
        - socket_options: Optional socket options to apply to created sockets.
        """
        self._origin = origin
        self._ssl_context = ssl_context
        self._keepalive_expiry = keepalive_expiry
        self._http1 = http1
        self._http2 = http2
        self._retries = retries
        self._local_address = local_address
        self._uds = uds

        self._network_backend: NetworkBackend = (
            SyncBackend() if network_backend is None else network_backend
        )
        self._connection: ConnectionInterface | None = None
        self._connect_failed: bool = False
        self._request_lock = Lock()
        self._socket_options = socket_options

    def handle_request(self, request: Request) -> Response:
        """
        Send a Request on this connection, establishing an underlying network
        stream (and protocol-specific ConnectionInterface) if necessary.

        This will ensure the connection is to the same origin as the request
        and will negotiate/instantiate an HTTP/1.1 or HTTP/2 connection based
        on ALPN or configuration.
        """
        if not self.can_handle_request(request.url.origin):
            raise RuntimeError(
                f"Attempted to send request to {request.url.origin} on connection to {self._origin}"
            )

        try:
            with self._request_lock:
                if self._connection is None:
                    stream = self._connect(request)

                    ssl_object = stream.get_extra_info("ssl_object")
                    http2_negotiated = (
                        ssl_object is not None
                        and ssl_object.selected_alpn_protocol() == "h2"
                    )
                    if http2_negotiated or (self._http2 and not self._http1):
                        from .http2 import HTTP2Connection

                        self._connection = HTTP2Connection(
                            origin=self._origin,
                            stream=stream,
                            keepalive_expiry=self._keepalive_expiry,
                        )
                    else:
                        self._connection = HTTP11Connection(
                            origin=self._origin,
                            stream=stream,
                            keepalive_expiry=self._keepalive_expiry,
                        )
        except BaseException as exc:
            self._connect_failed = True
            raise exc

        return self._connection.handle_request(request)

    def _connect(self, request: Request) -> NetworkStream:
        """
        Establish a network stream to the origin for the given request.

        This method handles retries with exponential backoff, supports connecting
        over TCP or a Unix domain socket (UDS), and will perform TLS wrapping
        for secure origins. It returns a NetworkStream object representing the
        connected stream.
        """
        timeouts = request.extensions.get("timeout", {})
        sni_hostname = request.extensions.get("sni_hostname", None)
        timeout = timeouts.get("connect", None)

        retries_left = self._retries
        delays = exponential_backoff(factor=RETRIES_BACKOFF_FACTOR)

        last_error: Exception | None = None

        while True:
            try:
                # Build a base stream via the network backend. Different backends
                # expose different APIs; try common names in order.
                if self._uds is None:
                    # TCP connect
                    open_tcp = getattr(self._network_backend, "open_tcp_stream", None)
                    if open_tcp is None:
                        open_tcp = getattr(self._network_backend, "open_connection", None)
                    if open_tcp is None:
                        raise ConnectError("Network backend does not support TCP connects")

                    stream = open_tcp(
                        host=self._origin.host,
                        port=self._origin.port,
                        timeout=timeout,
                        local_address=self._local_address,
                        socket_options=self._socket_options,
                    )
                else:
                    # UDS connect
                    open_uds = getattr(self._network_backend, "open_unix_stream", None)
                    if open_uds is None:
                        raise ConnectError("Network backend does not support Unix domain sockets")
                    stream = open_uds(path=self._uds, timeout=timeout)

                # If TLS is required (https scheme or explicit SNI provided),
                # perform TLS wrapping via the backend if available, or via a
                # stream-level start_tls method.
                needs_tls = self._origin.scheme == "https" or sni_hostname is not None
                if needs_tls:
                    ssl_context = self._ssl_context or default_ssl_context()
                    backend_wrap = getattr(self._network_backend, "wrap_ssl", None)
                    server_hostname = sni_hostname or self._origin.host
                    if backend_wrap is not None:
                        stream = backend_wrap(stream, ssl_context=ssl_context, server_hostname=server_hostname, timeout=timeout)
                    else:
                        start_tls = getattr(stream, "start_tls", None)
                        if callable(start_tls):
                            stream = start_tls(ssl_context=ssl_context, server_hostname=server_hostname, timeout=timeout)
                        else:
                            # No way to perform TLS with this backend/stream.
                            raise ConnectError("Cannot perform TLS handshake: backend/stream lacks TLS support")

                return stream

            except ConnectTimeout as exc:
                last_error = exc
                # On timeouts, do not retry.
                raise

            except Exception as exc:
                last_error = exc
                if retries_left <= 0:
                    raise ConnectError(exc) from exc

                # Sleep according to exponential backoff, then retry.
                delay = next(delays)
                logger.debug("Connection failed, retrying in %s seconds: %s", delay, exc)
                try:
                    sleep_fn = getattr(self._network_backend, "sleep", None)
                    if callable(sleep_fn):
                        sleep_fn(delay)
                    else:
                        # Fallback to a simple busy-wait if backend does not provide sleep.
                        import time

                        time.sleep(delay)
                except Exception:
                    pass
                retries_left -= 1
                continue

        # If we exit loop unexpectedly, raise the last error.
        if last_error is not None:
            raise ConnectError(last_error)
        raise ConnectError("Failed to connect for unknown reasons")

    def can_handle_request(self, origin: Origin) -> bool:
        """
        Return True if this connection can handle a request for the given origin.

        A connection can handle a request if the origin matches this connection's
        origin, or if an existing underlying protocol connection says it can
        handle the origin (for example, a multiplexed HTTP/2 connection).
        """
        if origin == self._origin:
            return True
        if self._connection is not None:
            return self._connection.can_handle_request(origin)
        return False

    def close(self) -> None:
        """
        Close the underlying connection (if any) and mark this wrapper as closed.
        """
        if self._connection is not None:
            try:
                self._connection.close()
            finally:
                self._connection = None
        self._connect_failed = True

    def is_available(self) -> bool:
        """
        Return True if this connection is available for use.

        A connection is considered available if it has not had a fatal connect
        failure, and either no underlying connection has been established yet
        (so it can attempt a new connection), or the existing underlying
        connection reports it is available.
        """
        if self._connect_failed:
            return False
        if self._connection is None:
            return True
        return self._connection.is_available()

    def has_expired(self) -> bool:
        """
        Return True if the underlying connection has expired and should not be reused.
        """
        if self._connection is None:
            return False
        return self._connection.has_expired()

    def is_idle(self) -> bool:
        """
        Return True if the underlying connection is currently idle.
        """
        if self._connection is None:
            return True
        return self._connection.is_idle()

    def is_closed(self) -> bool:
        """
        Return True if the underlying connection has been closed.
        """
        if self._connection is None:
            # If we never established a connection and connect previously failed,
            # consider it closed. Otherwise, it's not closed.
            return self._connect_failed
        return self._connection.is_closed()

    def info(self) -> dict:
        """
        Return informational data about the underlying connection.

        The returned dict is backend/implementation-specific, but typically
        includes items such as peer address, socket details, and TLS info.
        """
        if self._connection is None:
            return {"origin": self._origin, "connected": False}
        try:
            return self._connection.info()
        except Exception:
            return {"origin": self._origin, "connected": True}

    def __repr__(self) -> str:
        """
        Return the canonical string representation for debugging.
        """
        status = "closed" if self.is_closed() else "open"
        backend_name = getattr(self._network_backend, "__class__", type(self._network_backend)).__name__
        return f"<HTTPConnection {self._origin!r} [{status}] backend={backend_name}>"

    def __enter__(self) -> "HTTPConnection":
        """
        Enter a context manager for the connection. Returns self.
        """
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        """
        Exit the context manager, closing the connection.
        """
        self.close()